import os,re
root="AlgebraicJacobian"
# map module name -> file
def mod2file(m):
    return m.replace('.','/')+'.lean'
def imports(f):
    out=[]
    try:
        for line in open(f):
            line=line.strip()
            if line.startswith('import '):
                m=line.split()[1]
                out.append(m)
            elif line and not line.startswith('--') and not line.startswith('import') and not line.startswith('/-') :
                # imports must be at top; stop once real code
                if line.startswith('open') or line.startswith('namespace') or line.startswith('set_option') or line.startswith('universe') or line.startswith('/-') or line.startswith('section'):
                    break
        return out
    except FileNotFoundError:
        return None

seen=set()
stack=['AlgebraicJacobian.Picard.IdentityComponent']
cohomology_hits=set()
missing=set()
while stack:
    m=stack.pop()
    if m in seen: continue
    seen.add(m)
    if m=='Mathlib' or m.startswith('Mathlib.') or m.startswith('Lean') or m.startswith('Batteries') or m.startswith('Aesop') or m.startswith('Init') or m.startswith('Std'):
        continue
    f=mod2file(m)
    imps=imports(f)
    if imps is None:
        missing.add(m); continue
    for i in imps:
        if 'Cohomology' in i or 'Cech' in i or 'BaseChange' in i or 'FlatBase' in i:
            cohomology_hits.add((m,i))
        stack.append(i)

print("=== AJC modules in cone (non-mathlib):", len([s for s in seen if s.startswith('AlgebraicJacobian')]))
print("\n=== COHOMOLOGY/CECH/BASECHANGE edges in cone ===")
for a,b in sorted(cohomology_hits):
    print(f"  {a}  ->  {b}")
print("\n=== MISSING files (couldn't resolve) ===")
for m in sorted(missing):
    print("  ",m)
print("\n=== All AJC modules in cone ===")
for m in sorted(s for s in seen if s.startswith('AlgebraicJacobian')):
    print("  ",m)
